// Share URLs (for linking)
export const HEYGEN_VIDEO_URLS: Record<string, string> = Object.fromEntries(
  Object.entries(HEYGEN_VIDEO_IDS).map(([key, id]) => [
    key,
    `https://app.heygen.com/share/${id}`,
  ])
);

/**
 * Get the HeyGen embed URL for a lesson
 * @param lessonId - The lesson ID (e.g., 'autism-m1-l1')
 * @returns The embed URL or undefined if not found
 */
export function getHeyGenEmbedUrl(lessonId: string): string | undefined {
  const videoId = HEYGEN_VIDEO_IDS[lessonId];
  if (!videoId) return undefined;
  return `https://app.heygen.com/embed/${videoId}`;
}

/**
 * Get the HeyGen share URL for a lesson
 * @param lessonId - The lesson ID (e.g., 'autism-m1-l1')
 * @returns The share URL or undefined if not found
 */
export function getVideoUrl(lessonId: string): string | undefined {
  return HEYGEN_VIDEO_URLS[lessonId];
}

/**
 * Check if a lesson has a HeyGen video
 * @param lessonId - The lesson ID
 * @returns true if the lesson has a HeyGen video
 */
export function hasHeyGenVideo(lessonId: string): boolean {
  return lessonId in HEYGEN_VIDEO_IDS;
}

/**
 * Extract lesson ID from a content URL path
 * @param contentUrl - The local content URL (e.g., '/content/training_videos/autism-spectrum-support/autism-m1-l1.mp4')
 * @returns The lesson ID (e.g., 'autism-m1-l1') or undefined
 */
export function extractLessonIdFromUrl(contentUrl: string): string | undefined {
  const match = contentUrl.match(/(autism|adhd|dyslexia)-m\d+-l\d+/);
  return match ? match[0] : undefined;
}
